final:
module RefModule(
    input               clk,
    input               rst,

    output reg [4:0]    count
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or posedge rst or posedge dbg_halt) begin
    if (rst)
        count <= 5'b00001;
    else
        count <= {count[3:0], count[4]};
end

endmodule
